def briefing(rows):
    if not rows:
        return [{
            "title": "GitHub Activity Briefing",
            "body_markdown": "No commits returned from github_list_commits.",
        }]
    repo = rows[0].get("repo", "")
    body = "# GitHub Activity Briefing\n\n"
    if repo:
        body += "**Repository:** " + str(repo) + "\n\n"
    body += "## Recent commits\n"
    for r in rows:
        body += "- " + str(r.get("author", "")) + ": " + str(r.get("message", "")) + " (" + str(r.get("commit_sha", "")) + ")\n"
    return [{
        "title": "GitHub Activity Briefing" + (" — " + str(repo) if repo else ""),
        "body_markdown": body,
    }]

